insert into public.faq_entries (id, question, answer, category, sort_order, is_active) values ('09bfb5f3-40c8-58fa-88c0-0763f014deab', 'How is this different from other coaching or habit apps?', 'Most apps reset to zero context every session. Executive Coach AI builds a persistent behavioral model of you over months — tracking your task completion patterns, emotional triggers, and avoidance cycles. The coaching gets sharper the longer you stay, because it''s drawing from your actual history instead of generic advice.', 'Getting Started', 1, true) on conflict (id) do nothing;
insert into public.faq_entries (id, question, answer, category, sort_order, is_active) values ('e9e0784a-3a00-5f74-84d3-9b6a2a0b1369', 'Is this designed for people with ADHD?', 'Yes. It''s built specifically for high-earning professionals with ADHD who struggle with avoidance cycles, drift, and inconsistent follow-through. The real-time nudges detect when you''re slipping and intervene before a bad day becomes a bad week.', 'Getting Started', 2, true) on conflict (id) do nothing;
insert into public.faq_entries (id, question, answer, category, sort_order, is_active) values ('d320225d-4a90-5fee-8c76-7ff45e7fe6f5', 'What is a weekly retrospective?', 'Each week the app generates a structured review built entirely from your own behavioral data — what you completed, where you stalled, which triggers preceded avoidance, and what patterns are emerging. It''s not a generic template; it''s a mirror of your actual week with concrete next steps.', 'Features', 3, true) on conflict (id) do nothing;
insert into public.faq_entries (id, question, answer, category, sort_order, is_active) values ('952b9cb7-9155-59e9-8594-5ea61cb7c782', 'How do the real-time nudges work?', 'The app watches for drift — a stalled task, a skipped routine, an emotional trigger it has learned correlates with avoidance — and sends a timely, specific nudge. Because it knows your patterns, nudges are personalized rather than the same reminder everyone gets.', 'Features', 4, true) on conflict (id) do nothing;
insert into public.faq_entries (id, question, answer, category, sort_order, is_active) values ('89fee4e4-1777-5255-83b8-f1ed55216b1f', 'Is my behavioral data private and secure?', 'Your behavioral model is yours. Data is encrypted in transit and at rest, and we never sell it. You can export or delete your full history at any time from settings.', 'Privacy & Data', 5, true) on conflict (id) do nothing;
insert into public.faq_entries (id, question, answer, category, sort_order, is_active) values ('a0125c90-e72f-5454-8b02-8b4eabaa83d9', 'How long before the coaching feels accurate?', 'You''ll get useful structure in the first week, but the model meaningfully compounds over the first 30 to 60 days as it learns your cycles. Unlike a session-based coach, the value increases the longer you stay engaged.', 'Getting Started', 6, true) on conflict (id) do nothing;
